All specialized template handlers follow this consistent pattern:

```cpp
static common_chat_params common_chat_params_init_[MODEL_NAME](
    const common_chat_template &            tmpl,
    const autoparser::generation_params &   inputs) {

    common_chat_params data;

    // 1. Prepare adjusted messages if needed
    auto adjusted_messages = json::array();
    // ... message transformation logic ...

    // 2. Apply template with adjusted messages
    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs, adjusted_messages);

    // 3. Set output format
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    // 4. Define preserved tokens (prevent tokenization)
    data.preserved_tokens = {
        "[TOKEN1]",
        "[TOKEN2]",
        // ...
    };

    // 5. Build custom PEG parser using peg_builder
    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        // Customize parsing rules
        return p.prefix(generation_prompt) + (reasoning << p.content(p.rest()));
    });

    data.parser = parser.save();

    // 6. Optional: Build grammar for tool calls
    if (include_grammar) {
        data.grammar_lazy = ...;
        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            // Build tool calling grammar
            parser.build_grammar(builder, data.grammar_lazy);
        });
        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TOOL_CALLS]" }
        };
    }

    // 7. Optional: Support thinking/reasoning
    data.supports_thinking = true;
    data.thinking_start_tag = "[THINK]";
    data.thinking_end_tag = "[/THINK]";

    return data;
}
```

