130	    if (cp >= 32 && cp < 127) {
131	        return std::string("'") + static_cast<char>(cp) + "'";
132	    } else if (cp == '\n') {
133	        return "'\\n'";
134	    } else if (cp == '\r') {
135	        return "'\\r'";
136	    } else if (cp == '\t') {
